INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('54e867d3-0000-4000-8000-0e0000ca0e00', 'Scale', 'Armored or soft scale insects attached to stems and leaves.', 'Brown bumps, yellowing, sticky residue', 'Citrus, ficus, orchids, palms', 'Rub off with alcohol swab; horticultural oil sprays', 'Inspect purchases; quarantine new plants', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
