INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('49d5c0df-0000-4000-8000-0e0000000ef0', 'Whiteflies', 'Small white flying insects on leaf undersides.', 'Cloud of flies when plant is disturbed', 'Tomatoes, hibiscus, poinsettia, citrus', 'Yellow sticky traps; insecticidal soap', 'Remove heavily infested leaves early', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('3859e489-0000-4000-8000-0e000f000000', 'Fungus gnats', 'Small flies whose larvae feed on wet organic soil.', 'Tiny flies around soil; larvae in top inch of soil', 'Overwatered houseplants, seedlings', 'Let soil dry; BTI drench; sticky traps', 'Avoid soggy soil; top dress with sand', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('4a279185-0000-4000-8000-0e0000000000', 'Thrips', 'Slender insects that scrape leaf tissue leaving silvery scars.', 'Silvery streaks, distorted buds, black specks', 'Roses, onions, gladiolus, many ornamentals', 'Spinosad or neem; remove affected flowers', 'Reflective mulch in vegetable beds', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('a0e8df7d-0000-4000-8000-0e000ca0e000', 'Caterpillars', 'Larval stage of moths and butterflies that chew foliage.', 'Holes in leaves, frass (droppings), visible larvae', 'Brassicas, tomatoes, fruit trees', 'Hand-pick; Bt (Bacillus thuringiensis) spray', 'Row covers on seedlings', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('54ecc9b1-0000-4000-8000-0e0000000000', 'Slugs and snails', 'Moisture-loving mollusks active at night.', 'Irregular holes, slime trails', 'Hostas, lettuce, strawberries', 'Beer traps, iron phosphate bait, hand pick at dusk', 'Reduce mulch moisture; copper barriers', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('f811d9c9-0000-4000-8000-0e0000eaf000', 'Leaf miners', 'Larvae tunnel between leaf layers leaving visible trails.', 'Serpentine white trails in leaves', 'Citrus, spinach, beets, ornamentals', 'Remove affected leaves; spinosad for severe cases', 'Monitor early; avoid over-head watering', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('f4f6b610-0000-4000-8000-0e0000a0a0e0', 'Japanese beetles', 'Metallic green beetles that skeletonize leaves.', 'Lacy damaged leaves, beetles on flowers', 'Roses, grapes, raspberries, linden', 'Hand pick into soapy water; neem on early larvae', 'Grub control in lawn if recurring', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('65cdefc3-0000-4000-8000-0e000a000000', 'Ants (farming pests)', 'Ants protect aphids and scale for honeydew.', 'Ant trails on stems; paired with sap-suckers', 'Citrus, peonies, many garden plants', 'Control underlying pest; ant baits at trails', 'Sticky barriers on tree trunks', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('8dd2389e-0000-4000-8000-0e000c000000', 'Cutworms', 'Soil-dwelling larvae that cut seedlings at soil line.', 'Seedlings fallen over, severed at base', 'Tomatoes, peppers, young transplants', 'Collars around stems; hunt at night', 'Clear debris; rotate crops', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('53fe8bbb-0000-4000-8000-0e000b00e000', 'Stem borers', 'Larvae tunnel into stems causing wilting.', 'Entry holes, frass, sudden branch wilt', 'Squash, roses, fruit trees', 'Slit stem to remove larva; destroy affected stems', 'Remove plant debris; trap crops', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO pests (id, name, description, signs, affected_plants, treatment, prevention, image_url) VALUES ('f2a4fd3f-0000-4000-8000-0e000000a0c0', 'Whitefly & aphid (virus vectors)', 'Sap feeders that spread viral diseases between plants.', 'Mottled leaves plus insect presence', 'Tomatoes, peppers, cucurbits', 'Remove infected plants; control vectors', 'Resistant varieties; reflective mulch', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('d633accb-0000-4000-8000-d00000000000', 'Root rot', 'Fungal decay of roots from prolonged soggy soil.', 'Yellowing, wilting despite wet soil, mushy roots', 'Overwatering, poor drainage, compacted soil', 'Houseplants, succulents, trees in wet sites', 'Repot in fresh mix; trim rotten roots; fungicide drench', 'Well-draining soil; water only when needed', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('84d6a072-0000-4000-8000-d000000de000', 'Powdery mildew', 'White powdery fungal coating on leaf surfaces.', 'White dusty patches on leaves and stems', 'High humidity, poor airflow, shade', 'Squash, roses, grapes, peonies', 'Neem, potassium bicarbonate, sulfur spray', 'Space plants; morning watering; resistant varieties', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('6b60f392-0000-4000-8000-d0000eaf0000', 'Leaf spot', 'Fungal or bacterial spots on foliage.', 'Brown or black circular spots, yellow halos', 'Splashing water, wet foliage, infected debris', 'Tomatoes, hydrangeas, many ornamentals', 'Remove affected leaves; copper fungicide', 'Drip irrigation; sanitize tools', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('0d50ddc3-0000-4000-8000-d00000000000', 'Rust', 'Orange/rust-colored fungal pustules on leaf undersides.', 'Orange powdery spots, premature leaf drop', 'Moist leaves, cool nights, spores from debris', 'Roses, hollyhocks, beans, daylilies', 'Remove infected leaves; fungicide early season', 'Clean fall debris; improve air circulation', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('e0bf6c13-0000-4000-8000-d000b0000000', 'Blight', 'Rapid browning and collapse of leaves and stems.', 'Dark lesions spreading quickly, plant collapse', 'Wet weather, infected seed, soil splash', 'Tomatoes, potatoes, peppers', 'Remove infected tissue; copper or chlorothalonil', 'Rotate crops; stake plants; resistant cultivars', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('a369d52b-0000-4000-8000-d000c0000000', 'Citrus greening', 'Bacterial disease spread by Asian citrus psyllid.', 'Asymmetric yellow mottling, bitter misshapen fruit', 'Candidatus Liberibacter; psyllid vector', 'All citrus species', 'No cure — remove tree to protect neighbors', 'Control psyllids; buy certified disease-free stock', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('3b294ca7-0000-4000-8000-d000a0000ac0', 'Anthracnose', 'Fungal disease causing sunken lesions on leaves and fruit.', 'Dark sunken spots, twig dieback', 'Wet spring weather, spores on debris', 'Dogwood, sycamore, tomatoes, avocados', 'Prune infected wood; fungicide at bud break', 'Rake fallen leaves; avoid overhead irrigation', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('be287eac-0000-4000-8000-d000f00e0b00', 'Fire blight', 'Bacterial disease that blackens blossoms and shoots.', 'Blackened hook-shaped shoots, oozing cankers', 'Erwinia amylovora; warm wet bloom weather', 'Apple, pear, crabapple, pyracantha', 'Prune 12 in below infection in dry weather', 'Avoid high-nitrogen spring feed; resistant varieties', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('60af7def-0000-4000-8000-d000b0000000', 'Botrytis (gray mold)', 'Gray fuzzy mold on flowers and soft tissue.', 'Gray mold on blooms, soft rotting tissue', 'Cool humid conditions, dead plant material', 'Strawberries, roses, geraniums, lettuce', 'Remove affected parts; improve airflow; fungicide', 'Deadhead; avoid crowding; reduce humidity indoors', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('559d751b-0000-4000-8000-d000d0000000', 'Downy mildew', 'Fuzzy gray growth on leaf undersides.', 'Yellow patches on top, gray fuzz below', 'Cool wet nights, high humidity', 'Impatiens, basil, cucumbers, grapes', 'Fungicide labeled for downy mildew; remove plants', 'Resistant varieties; avoid evening watering', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('672c2922-0000-4000-8000-d0000e000c00', 'Verticillium wilt', 'Soil-borne fungus blocking water transport.', 'One-sided wilting, brown streaks in vascular tissue', 'Verticillium in soil; persists for years', 'Maple, tomato, eggplant, stone fruits', 'No cure — remove plant; solarize soil if possible', 'Crop rotation; resistant rootstocks', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('4afed4af-0000-4000-8000-d000b0ac0000', 'Black spot', 'Common rose fungal disease.', 'Black spots with yellow halos, defoliation', 'Splashing water, warm humid weather', 'Roses primarily', 'Remove fallen leaves; fungicide program', 'Plant resistant cultivars; mulch under roses', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('3af1d1fc-0000-4000-8000-d000b0000000', 'Blossom end rot', 'Calcium deficiency disorder on fruit, not a pathogen.', 'Dark leathery patch on blossom end of fruit', 'Calcium uptake blocked by irregular watering', 'Tomatoes, peppers, squash', 'Consistent watering; calcium foliar spray if needed', 'Mulch; avoid drought stress', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('80762142-0000-4000-8000-d000c0000000', 'Crown rot', 'Rot at base of plant from soil-line moisture.', 'Collapse at crown, foul-smelling base', 'Deep planting, mulch against stem, poor drainage', 'Strawberries, succulents, trees', 'Improve drainage; fungicide; may need replacement', 'Plant at correct depth; keep mulch away from stem', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO diseases (id, name, description, symptoms, causes, affected_plants, treatment, prevention, image_url) VALUES ('803a72d9-0000-4000-8000-d000000a0c00', 'Mosaic virus', 'Viral infection causing mottled leaf patterns.', 'Mottled yellow-green leaves, stunted growth', 'Aphids, seeds, infected tools', 'Tomatoes, cucumbers, many ornamentals', 'Remove infected plants; control vectors', 'Virus-free seed; sanitize tools; weed hosts', 'https://images.unsplash.com/photo-1416879595882-337324a7f4f9?w=400&h=300&fit=crop&q=80') ON CONFLICT (name) DO NOTHING;
INSERT INTO plant_care_guides (id, plant_species_id, watering_guide, sunlight_guide, soil_guide, fertilizer_guide, pruning_guide, repotting_guide, seasonal_care, common_problems, beginner_tips) VALUES ('ef829139-0000-4000-8000-000de000ec0e', 'a7e42f88-0000-4000-8000-00ec0e000e0e', 'Deep water weekly; more in summer', 'Full sun (6+ hours)', 'Well-draining loam', 'Feed during active growth with a formula suited to tree plants. Reduce or stop in dormancy.', 'Prune dead or crossing branches in late winter. Shape lightly after bloom for flowering types.', 'Container plants benefit from repotting every 2–3 years with refreshed soil.', 'Zones 8–11: protect from extremes outside range. Adjust watering seasonally — less in winter for most plants.', 'Overwatering, insufficient light, and pest outbreaks are the most common issues. Match care to the plant''s native habits.', 'Start with consistent deep water weekly; more in summer. Place where it gets full sun (6+ hours). Check soil before watering.') ON CONFLICT (plant_species_id) DO NOTHING;
INSERT INTO plant_care_guides (id, plant_species_id, watering_guide, sunlight_guide, soil_guide, fertilizer_guide, pruning_guide, repotting_guide, seasonal_care, common_problems, beginner_tips) VALUES ('62893d5b-0000-4000-8000-000de000ec0e', '700c236a-0000-4000-8000-00ec0e000a0a', 'Deep water weekly; more in summer', 'Partial shade', 'Well-draining loam', 'Feed during active growth with a formula suited to tree plants. Reduce or stop in dormancy.', 'Prune dead or crossing branches in late winter. Shape lightly after bloom for flowering types.', 'Container plants benefit from repotting every 2–3 years with refreshed soil.', 'Zones 5–8: protect from extremes outside range. Adjust watering seasonally — less in winter for most plants.', 'Overwatering, insufficient light, and pest outbreaks are the most common issues. Match care to the plant''s native habits.', 'Start with consistent deep water weekly; more in summer. Place where it gets partial shade. Check soil before watering.') ON CONFLICT (plant_species_id) DO NOTHING;
